import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
describe("config", () => {
    const originalEnv = { ...process.env };
    beforeEach(() => {
        vi.resetModules();
        delete process.env.BITFAB_API_KEY;
        delete process.env.BITFAB_SERVICE_URL;
        delete process.env.BITFAB_VERBOSE;
        delete process.env.BITFAB_DEBUG;
    });
    afterEach(() => {
        process.env = { ...originalEnv };
    });
    async function importConfig() {
        return import("./config.js");
    }
    describe("getConfig env var overrides", () => {
        it("BITFAB_SERVICE_URL env var overrides file config", async () => {
            process.env.BITFAB_SERVICE_URL = "http://test:9999";
            const { getConfig } = await importConfig();
            expect(getConfig().serviceUrl).toBe("http://test:9999");
        });
        it("BITFAB_API_KEY env var overrides file credentials", async () => {
            process.env.BITFAB_API_KEY = "env-override-key";
            const { getConfig } = await importConfig();
            expect(getConfig().apiKey).toBe("env-override-key");
        });
        it("BITFAB_VERBOSE=true from env", async () => {
            process.env.BITFAB_VERBOSE = "true";
            const { getConfig } = await importConfig();
            expect(getConfig().verbose).toBe(true);
        });
        it("BITFAB_VERBOSE=1 from env", async () => {
            process.env.BITFAB_VERBOSE = "1";
            const { getConfig } = await importConfig();
            expect(getConfig().verbose).toBe(true);
        });
        it("BITFAB_VERBOSE=false from env", async () => {
            process.env.BITFAB_VERBOSE = "false";
            const { getConfig } = await importConfig();
            expect(getConfig().verbose).toBe(false);
        });
        it("BITFAB_VERBOSE=0 from env", async () => {
            process.env.BITFAB_VERBOSE = "0";
            const { getConfig } = await importConfig();
            expect(getConfig().verbose).toBe(false);
        });
        it("BITFAB_DEBUG=true from env", async () => {
            process.env.BITFAB_DEBUG = "true";
            const { getConfig } = await importConfig();
            expect(getConfig().debug).toBe(true);
        });
        it("BITFAB_DEBUG=1 from env", async () => {
            process.env.BITFAB_DEBUG = "1";
            const { getConfig } = await importConfig();
            expect(getConfig().debug).toBe(true);
        });
    });
    describe("project config (.bitfab/config.local.json)", () => {
        let tmpDir;
        beforeEach(() => {
            tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-config-test-"));
        });
        afterEach(() => {
            fs.rmSync(tmpDir, { recursive: true, force: true });
            vi.restoreAllMocks();
        });
        function writeProjectConfig(dir, data) {
            const bitfabDir = path.join(dir, ".bitfab");
            fs.mkdirSync(bitfabDir, { recursive: true });
            fs.writeFileSync(path.join(bitfabDir, "config.local.json"), `${JSON.stringify(data, null, 2)}\n`);
        }
        it("project config.local.json sets serviceUrl", async () => {
            writeProjectConfig(tmpDir, { serviceUrl: "http://project:1234" });
            vi.spyOn(process, "cwd").mockReturnValue(tmpDir);
            const { getConfig } = await importConfig();
            expect(getConfig().serviceUrl).toBe("http://project:1234");
        });
        it("BITFAB_SERVICE_URL env var beats project config", async () => {
            writeProjectConfig(tmpDir, { serviceUrl: "http://project:1234" });
            vi.spyOn(process, "cwd").mockReturnValue(tmpDir);
            process.env.BITFAB_SERVICE_URL = "http://env:9999";
            const { getConfig } = await importConfig();
            expect(getConfig().serviceUrl).toBe("http://env:9999");
        });
        it("walk-up finds project config from a nested subdirectory", async () => {
            writeProjectConfig(tmpDir, { serviceUrl: "http://project:1234" });
            const nested = path.join(tmpDir, "src", "deep", "nested");
            fs.mkdirSync(nested, { recursive: true });
            vi.spyOn(process, "cwd").mockReturnValue(nested);
            const { getConfig } = await importConfig();
            expect(getConfig().serviceUrl).toBe("http://project:1234");
        });
        it("project config without serviceUrl falls through (no crash)", async () => {
            writeProjectConfig(tmpDir, { someOtherKey: "value" });
            vi.spyOn(process, "cwd").mockReturnValue(tmpDir);
            const { getConfig } = await importConfig();
            const result = getConfig();
            expect(typeof result.serviceUrl).toBe("string");
            expect(result.serviceUrl.length).toBeGreaterThan(0);
        });
        it("malformed project config JSON does not crash", async () => {
            const bitfabDir = path.join(tmpDir, ".bitfab");
            fs.mkdirSync(bitfabDir, { recursive: true });
            fs.writeFileSync(path.join(bitfabDir, "config.local.json"), "{ not valid json");
            vi.spyOn(process, "cwd").mockReturnValue(tmpDir);
            const { getConfig } = await importConfig();
            expect(() => getConfig()).not.toThrow();
            expect(typeof getConfig().serviceUrl).toBe("string");
        });
        it("project config does not affect apiKey, verbose, or debug", async () => {
            vi.spyOn(process, "cwd").mockReturnValue(tmpDir);
            const { getConfig } = await importConfig();
            const baseline = getConfig();
            writeProjectConfig(tmpDir, {
                serviceUrl: "http://project:1234",
                verbose: !baseline.verbose,
                debug: !baseline.debug,
                apiKey: "project-key-should-not-leak",
            });
            const result = getConfig();
            expect(result.serviceUrl).toBe("http://project:1234");
            expect(result.verbose).toBe(baseline.verbose);
            expect(result.debug).toBe(baseline.debug);
            expect(result.apiKey).toBe(baseline.apiKey);
        });
    });
    describe("project credentials (.bitfab/credentials.local.json)", () => {
        let tmpDir;
        beforeEach(() => {
            tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-creds-test-"));
        });
        afterEach(() => {
            fs.rmSync(tmpDir, { recursive: true, force: true });
            vi.restoreAllMocks();
        });
        function writeProjectCredentials(dir, data) {
            const bitfabDir = path.join(dir, ".bitfab");
            fs.mkdirSync(bitfabDir, { recursive: true });
            fs.writeFileSync(path.join(bitfabDir, "credentials.local.json"), `${JSON.stringify(data, null, 2)}\n`);
        }
        it("project credentials override global apiKey", async () => {
            writeProjectCredentials(tmpDir, { apiKey: "project-key" });
            vi.spyOn(process, "cwd").mockReturnValue(tmpDir);
            const { getConfig } = await importConfig();
            expect(getConfig().apiKey).toBe("project-key");
        });
        it("empty project credentials file blocks global fallback", async () => {
            writeProjectCredentials(tmpDir, {});
            vi.spyOn(process, "cwd").mockReturnValue(tmpDir);
            const { getConfig } = await importConfig();
            expect(getConfig().apiKey).toBeNull();
        });
        it("BITFAB_API_KEY env var beats project credentials", async () => {
            writeProjectCredentials(tmpDir, { apiKey: "project-key" });
            vi.spyOn(process, "cwd").mockReturnValue(tmpDir);
            process.env.BITFAB_API_KEY = "env-key";
            const { getConfig } = await importConfig();
            expect(getConfig().apiKey).toBe("env-key");
        });
        it("walk-up finds project credentials from nested subdirectory", async () => {
            writeProjectCredentials(tmpDir, { apiKey: "nested-key" });
            const nested = path.join(tmpDir, "src", "deep");
            fs.mkdirSync(nested, { recursive: true });
            vi.spyOn(process, "cwd").mockReturnValue(nested);
            const { getConfig } = await importConfig();
            expect(getConfig().apiKey).toBe("nested-key");
        });
        it("hasCredentials returns false when project credentials is empty", async () => {
            writeProjectCredentials(tmpDir, {});
            vi.spyOn(process, "cwd").mockReturnValue(tmpDir);
            const { hasCredentials } = await importConfig();
            expect(hasCredentials()).toBe(false);
        });
        it("malformed project credentials JSON preserves isolation", async () => {
            const bitfabDir = path.join(tmpDir, ".bitfab");
            fs.mkdirSync(bitfabDir, { recursive: true });
            fs.writeFileSync(path.join(bitfabDir, "credentials.local.json"), "{ not valid json");
            vi.spyOn(process, "cwd").mockReturnValue(tmpDir);
            const { getConfig } = await importConfig();
            expect(() => getConfig()).not.toThrow();
            expect(getConfig().apiKey).toBeNull();
        });
    });
    describe("getConfig returns valid structure", () => {
        it("returns all expected fields", async () => {
            const { getConfig } = await importConfig();
            const config = getConfig();
            expect(config).toHaveProperty("serviceUrl");
            expect(config).toHaveProperty("apiKey");
            expect(config).toHaveProperty("verbose");
            expect(config).toHaveProperty("debug");
            expect(typeof config.serviceUrl).toBe("string");
            expect(typeof config.verbose).toBe("boolean");
            expect(typeof config.debug).toBe("boolean");
        });
        it("serviceUrl is a valid URL", async () => {
            const { getConfig } = await importConfig();
            const { serviceUrl } = getConfig();
            expect(() => new URL(serviceUrl)).not.toThrow();
        });
    });
    describe("hasCredentials", () => {
        it("returns true when env var is set", async () => {
            process.env.BITFAB_API_KEY = "env-key";
            const { hasCredentials } = await importConfig();
            expect(hasCredentials()).toBe(true);
        });
    });
    describe("saveCredentials and deleteCredentials", () => {
        const configDir = path.join(os.homedir(), ".config", "bitfab");
        const credFile = path.join(configDir, "credentials.json");
        let existingCreds;
        let tmpDir;
        beforeEach(() => {
            tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-save-creds-"));
            vi.spyOn(process, "cwd").mockReturnValue(tmpDir);
            try {
                existingCreds = fs.readFileSync(credFile, "utf-8");
            }
            catch {
                existingCreds = null;
            }
        });
        afterEach(() => {
            vi.restoreAllMocks();
            fs.rmSync(tmpDir, { recursive: true, force: true });
            if (existingCreds) {
                fs.writeFileSync(credFile, existingCreds);
            }
        });
        it("saveCredentials writes and reads back the key", async () => {
            const { saveCredentials, getConfig } = await importConfig();
            const testKey = `test-key-${Date.now()}`;
            saveCredentials(testKey);
            const content = JSON.parse(fs.readFileSync(credFile, "utf-8"));
            expect(content.apiKey).toBe(testKey);
            const config = getConfig();
            expect(config.apiKey).toBe(testKey);
            if (existingCreds) {
                fs.writeFileSync(credFile, existingCreds);
            }
            else {
                fs.unlinkSync(credFile);
            }
        });
        it("deleteCredentials removes the file", async () => {
            const { saveCredentials, deleteCredentials } = await importConfig();
            saveCredentials("key-to-delete");
            expect(fs.existsSync(credFile)).toBe(true);
            deleteCredentials();
            expect(fs.existsSync(credFile)).toBe(false);
            if (existingCreds) {
                fs.mkdirSync(configDir, { recursive: true });
                fs.writeFileSync(credFile, existingCreds);
            }
        });
        it("deleteCredentials does not throw when no file exists", async () => {
            const { deleteCredentials } = await importConfig();
            if (fs.existsSync(credFile)) {
                fs.unlinkSync(credFile);
            }
            expect(() => deleteCredentials()).not.toThrow();
            if (existingCreds) {
                fs.mkdirSync(configDir, { recursive: true });
                fs.writeFileSync(credFile, existingCreds);
            }
        });
        it("saveCredentials writes to project-local file when it exists", async () => {
            const { saveCredentials, getConfig } = await importConfig();
            const localDir = path.join(tmpDir, ".bitfab");
            const localFile = path.join(localDir, "credentials.local.json");
            fs.mkdirSync(localDir, { recursive: true });
            fs.writeFileSync(localFile, "{}\n");
            const testKey = `local-key-${Date.now()}`;
            saveCredentials(testKey);
            const localContent = JSON.parse(fs.readFileSync(localFile, "utf-8"));
            expect(localContent.apiKey).toBe(testKey);
            const config = getConfig();
            expect(config.apiKey).toBe(testKey);
        });
    });
    describe("sessionLogConsent", () => {
        const configDir = path.join(os.homedir(), ".config", "bitfab");
        const configFile = path.join(configDir, "config.json");
        let existingConfig;
        beforeEach(() => {
            try {
                existingConfig = fs.readFileSync(configFile, "utf-8");
            }
            catch {
                existingConfig = null;
            }
            try {
                fs.unlinkSync(configFile);
            }
            catch {
                // already gone
            }
        });
        afterEach(() => {
            if (existingConfig) {
                fs.mkdirSync(configDir, { recursive: true });
                fs.writeFileSync(configFile, existingConfig);
            }
            else {
                try {
                    fs.unlinkSync(configFile);
                }
                catch {
                    // already gone
                }
            }
        });
        it("getSessionLogConsent returns null when not set", async () => {
            const { getSessionLogConsent } = await importConfig();
            expect(getSessionLogConsent()).toBe(null);
        });
        it("setSessionLogConsent(true) persists and reads back as true", async () => {
            const { getSessionLogConsent, setSessionLogConsent } = await importConfig();
            setSessionLogConsent(true);
            expect(getSessionLogConsent()).toBe(true);
        });
        it("setSessionLogConsent(false) persists and reads back as false", async () => {
            const { getSessionLogConsent, setSessionLogConsent } = await importConfig();
            setSessionLogConsent(false);
            expect(getSessionLogConsent()).toBe(false);
        });
        it("setSessionLogConsent preserves other config fields", async () => {
            fs.mkdirSync(configDir, { recursive: true });
            fs.writeFileSync(configFile, `${JSON.stringify({ verbose: true, debug: false }, null, 2)}\n`);
            const { setSessionLogConsent } = await importConfig();
            setSessionLogConsent(true);
            const content = JSON.parse(fs.readFileSync(configFile, "utf-8"));
            expect(content.sessionLogConsent).toBe(true);
            expect(content.verbose).toBe(true);
            expect(content.debug).toBe(false);
        });
        it("getConfig exposes sessionLogConsent on BitfabConfig", async () => {
            const { getConfig, setSessionLogConsent } = await importConfig();
            expect(getConfig().sessionLogConsent).toBe(null);
            setSessionLogConsent(true);
            expect(getConfig().sessionLogConsent).toBe(true);
        });
    });
});
